mapper.select:
SELECT TBL.* , ROW_NUMBER() OVER(ORDER BY TBL.SSPS_DL_CRT_DT DESC, TBL.SSPS_DL_ID ASC) AS NU , CASE WHEN EXISTS (SELECT 1 FROM NIC80B_HIS WHERE SSPS_DL_CRT_DT = TBL.SSPS_DL_CRT_DT AND SSPS_DL_ID = TBL.SSPS_DL_ID AND KFU_RPR_STS_CD IN ('34','44','54') AND SND_RCPT_DOC_NO != TBL.INIT_DOC_NO) THEN 'Y' END AS ADD_YN , DECODE((SELECT COUNT(*) FROM NIC40B WHERE BAS_YYMM = TO_CHAR(ADD_MONTHS(TO_DATE(TBL.SSPS_DL_CRT_DT, 'YYYYMMDD'),-1),'YYYYMM') AND RNMCNO=TBL.DL_P_RNMCNO),0,'','Y') AS LGA_AST_YN , CASE WHEN TBL.SSPS_TYP_CD = 'KYC0' THEN '수기 등록' ELSE GET_SYNARIO_NAME(TBL.SSPS_TYP_CD) END AS SSPS_TYP_NM , (SELECT COUNT(*) FROM NIC73B WHERE SSPS_DL_CRT_DT = TBL.SSPS_DL_CRT_DT AND SSPS_DL_ID = TBL.SSPS_DL_ID) AS SSPS_DL_CNT , CASE WHEN RPR_PRGRS_CCD = '99' THEN TBL.SND_RCPT_FILE_NM END as TRSMT_ST_NM ,(SELECT MAX(SND_RCPT_FILE_NM) KEEP (DENSE_RANK FIRST ORDER BY RRPR_YN DESC, SQ DESC) FROM NIC80B_HIS WHERE SSPS_DL_CRT_DT = TBL.SSPS_DL_CRT_DT AND SSPS_DL_ID = TBL.SSPS_DL_ID AND RRPR_YN = 'Y' AND KFU_RPR_STS_CD = '99') AS TRSMT_ST_NM_RRPR , DECODE((SELECT COUNT(*) FROM NIC64B WHERE SSPS_DL_CRT_DT=TBL.SSPS_DL_CRT_DT AND SSPS_DL_ID=TBL.SSPS_DL_ID),0,'No','Yes') AS FILE_ATT_YN , NVL(TBL.MN_DL_DPRT_NM, (SELECT DPRT_NM FROM NIC41B Z WHERE DPRT_CD = TBL.MN_DL_DPRT_CD)) AS MN_DL_DPRT_NM , NVL(TBL.PRFT_BRN_NM, (SELECT DPRT_NM FROM NIC41B Z WHERE DPRT_CD = TBL.PRFT_BRN_CD)) AS PRFT_BRN_NM , CASE WHEN LENGTH(TBL.RPR_OGN_CD) = 4 THEN '보기' WHEN COALESCE(TBL.KFU_RRPR_STS_CD, TBL.KFU_RPR_STS_CD, TBL.RPR_PRGRS_CCD) IN ('10','40','50') THEN '보기' ELSE '수정' END AS XML_FILE_EDIT , GET_CODE_NAME('S060', NVL(TBL.KFU_RPR_STS_CD, TBL.RPR_PRGRS_CCD)) AS KFU_RPR_STS_NM , GET_CODE_NAME('S060', TBL.KFU_RRPR_STS_CD) AS KFU_RRPR_STS_NM , COALESCE(TBL.KFU_RRPR_STS_CD, TBL.KFU_RPR_STS_CD, TBL.RPR_PRGRS_CCD) AS ALL_RPR_STS_CD , GET_CODE_NAME('S060', COALESCE(TBL.KFU_RRPR_STS_CD, TBL.KFU_RPR_STS_CD, TBL.RPR_PRGRS_CCD)) AS ALL_RPR_STS_NM FROM (
SELECT '0' AS SELECTED, A.SSPS_DL_ID, A.SSPS_DL_CRT_DT, A.SSPS_DL_CRT_DT||'-'||REPLACE(A.SSPS_DL_ID,'CTR','STR') AS SSPS_DL_CRT_DT_A, B.DL_P_NM, A.DL_P_RNMCNO, A.SSPS_TYP_CD, A.SSPS_DL_ANLYS_BRN_CD AS MN_DL_BRN_CD, A.SSPS_DL_ANLYS_BRN_NM AS MN_DL_BRN_NM, A.RPR_PRGRS_CCD, GET_CODE_NAME('A029',A.RPR_PRGRS_CCD) AS RPR_CCD_NM, A.RPR_CHRG_P_NM, A.RPR_RSPSB_P_NM, CASE WHEN RPR_PRGRS_CCD = '99' THEN I.SND_RCPT_DOC_NO END AS DOC_NO, A.SSPS_DL_CRT_CCD, H.RSK_GRD_CD, GET_CODE_NAME('A004',H.RSK_GRD_CD) AS RSK_GRD_CD_NM, B.CS_NO, B.CS_NO AS AML_CUST_ID, B.INDV_CORP_CCD , A.RPR_DT, I.SND_RCPT_FILE_NM, A.OK_CCD, I.FIU_NO , I.FIU_REG_DT , G.GNL_AC_NO , G.ACNT_NO , G.MN_DL_DPRT_CD , G.MN_DL_DPRT_NM , G.PRFT_BRN_CD , G.PRFT_BRN_NM , A.TRIG_CTNT , A.XCL_RSN_CNTNT , I.SND_RCPT_DOC_NO
, TO_CHAR(A.KFU_RPR_DT, 'YYYYMMDD') AS KFU_RPR_DT , NVL(A.KFU_RPR_STS_CD, A.RPR_PRGRS_CCD) AS KFU_RPR_STS_CD
, A.KFU_RRPR_STS_CD
, NVL(A.RRPR_YN, 'N') AS RRPR_YN
, I.RPR_OGN_CD , (SELECT SUBSTR(MAX(RPR_P_DY_TM),1,8) FROM NIC66B_W WHERE INST_ID = A.INST_ID ) AS INST_DT , (SELECT MAX(SND_RCPT_DOC_NO) KEEP (DENSE_RANK FIRST ORDER BY RRPR_SQ, SQ) FROM NIC80B_HIS WHERE SSPS_DL_CRT_DT = A.SSPS_DL_CRT_DT AND SSPS_DL_ID = A.SSPS_DL_ID AND KFU_RPR_STS_CD = '10' AND ( (SND_RCPT_DOC_NO = I.SND_RCPT_DOC_NO AND A.KFU_RPR_STS_CD IN ('34','44','54')) OR SND_RCPT_DOC_NO != I.SND_RCPT_DOC_NO ) ) AS INIT_DOC_NO --최초문서번호 , B.SPRN_KEEP_TAGT_YN FROM NIC66B A, NIC70B B, NIC35B H, NIC80B I, (SELECT SSPS_DL_CRT_DT , SSPS_DL_ID , GNL_AC_NO , MN_DL_DPRT_CD , MN_DL_DPRT_NM , PRFT_BRN_CD , PRFT_BRN_NM , ACNT_NO FROM NIC71B WHERE (SSPS_DL_CRT_DT, SSPS_DL_ID, GNL_AC_NO) IN (SELECT X.SSPS_DL_CRT_DT, X.SSPS_DL_ID, MIN(X.GNL_AC_NO) FROM NIC71B X , NIC66B Y WHERE X.SSPS_DL_CRT_DT = Y.SSPS_DL_CRT_DT AND X.SSPS_DL_ID = Y.SSPS_DL_ID AND X.RNMCNO = Y.DL_P_RNMCNO GROUP BY X.SSPS_DL_CRT_DT, X.SSPS_DL_ID) ) G WHERE A.SSPS_DL_CRT_DT = B.SSPS_DL_CRT_DT(+) AND A.DL_P_RNMCNO = B.DL_P_RNMCNO(+) AND A.DL_P_RNMCNO = H.RNMCNO (+) AND A.SSPS_DL_CRT_DT = I.SSPS_DL_CRT_DT(+) AND A.SSPS_DL_ID = I.SSPS_DL_ID(+) AND A.SSPS_DL_CRT_DT = G.SSPS_DL_CRT_DT(+) AND A.SSPS_DL_ID = G.SSPS_DL_ID(+) AND A.SSPS_DL_CRT_CCD IN ( 'STR', 'KYC')
AND A.SSPS_DL_CRT_DT BETWEEN #{startDate} AND #{endDate}
AND TO_CHAR(A.KFU_RPR_DT,'YYYYMMDD') BETWEEN #{startDate} AND #{endDate}
AND #{branchCode} IN (SELECT MN_DL_BRN_CD FROM NIC73B WHERE SSPS_DL_CRT_DT = A.SSPS_DL_CRT_DT AND SSPS_DL_ID = A.SSPS_DL_ID)
AND OK_CCD = #{OK_CCD}
AND UPPER(DL_P_NM) like '%'||UPPER(#{CS_NM})||'%'
AND CS_NO = #{CS_NO}
AND A.DL_P_RNMCNO = (SELECT RNMCNO FROM NIC17B WHERE ACNT_NO LIKE #{ACNT_NO} || '%')
AND COALESCE(A.KFU_RRPR_STS_CD, A.KFU_RPR_STS_CD, A.RPR_PRGRS_CCD) = #{RPR_PRGRS_CCD}
AND A.RPR_PRGRS_CCD IN ('9', '99', '98', '97')
AND A.SSPS_DL_CRT_CCD IN ('STR', 'KYC')
AND A.SSPS_TYP_CD IN
#{SSPS_TYP_CD_ARRAY}
AND EXISTS (SELECT 1 FROM SSQ.NIC102B Z WHERE Z.SSPS_DL_CRT_DT = A.SSPS_DL_CRT_DT AND Z.SSPS_DL_ID = A.SSPS_DL_ID AND Z.SSPS_DL_CRT_CCD IN ('STR', 'KYC')
AND Z.AFPR_NM LIKE '%'|| #{AFPR_NM} ||'%'
AND Z.AFPR_RNMCNO = (SELECT RNMCNO FROM SSQ.NIC01B WHERE CS_NO = #{AFPR_NO} )
)
) TBL

SELECT X.* , CASE WHEN EXISTS (SELECT 1 FROM NIC80B_HIS WHERE SSPS_DL_CRT_DT = X.SSPS_DL_CRT_DT AND SSPS_DL_ID = X.SSPS_DL_ID AND KFU_RPR_STS_CD IN ('34','44','54') AND SND_RCPT_DOC_NO != X.INIT_DOC_NO) THEN 'Y' END AS ADD_YN FROM ( SELECT * FROM (SELECT '0' AS SELECTED, A.SSPS_DL_ID, A.SSPS_DL_CRT_DT, A.SSPS_DL_CRT_DT||'-'||REPLACE(A.SSPS_DL_ID,'CTR','STR') AS SSPS_DL_CRT_DT_A, B.DL_P_NM, A.DL_P_RNMCNO, A.SSPS_TYP_CD, DECODE((SELECT COUNT(*) FROM NIC40B WHERE BAS_YYMM = TO_CHAR(ADD_MONTHS(TO_DATE(A.SSPS_DL_CRT_DT, 'YYYYMMDD'),-1),'YYYYMM') AND RNMCNO=A.DL_P_RNMCNO),0,'','Y') AS LGA_AST_YN ,CASE WHEN A.SSPS_TYP_CD = 'KYC0' THEN '수기 등록' ELSE GET_SYNARIO_NAME(A.SSPS_TYP_CD) END AS SSPS_TYP_NM, (SELECT COUNT(*) FROM NIC73B WHERE SSPS_DL_CRT_DT = A.SSPS_DL_CRT_DT AND SSPS_DL_ID = A.SSPS_DL_ID) AS SSPS_DL_CNT, A.SSPS_DL_ANLYS_BRN_CD AS MN_DL_BRN_CD, A.SSPS_DL_ANLYS_BRN_NM AS MN_DL_BRN_NM, A.RPR_PRGRS_CCD, GET_CODE_NAME('A029',A.RPR_PRGRS_CCD) AS RPR_CCD_NM, A.RPR_CHRG_P_NM, A.RPR_RSPSB_P_NM, CASE WHEN RPR_PRGRS_CCD = '99' THEN I.SND_RCPT_DOC_NO END AS DOC_NO, A.SSPS_DL_CRT_CCD, H.RSK_GRD_CD, GET_CODE_NAME('A004',H.RSK_GRD_CD) AS RSK_GRD_CD_NM, B.CS_NO, B.INDV_CORP_CCD , CASE WHEN RPR_PRGRS_CCD = '99' THEN I.SND_RCPT_FILE_NM END as TRSMT_ST_NM, (SELECT MAX(SND_RCPT_FILE_NM) KEEP (DENSE_RANK FIRST ORDER BY RRPR_YN DESC, SQ DESC) FROM NIC80B_HIS WHERE SSPS_DL_CRT_DT = A.SSPS_DL_CRT_DT AND SSPS_DL_ID = A.SSPS_DL_ID AND RRPR_YN = 'Y' AND KFU_RPR_STS_CD = '99') AS TRSMT_ST_NM_RRPR, A.RPR_DT, I.SND_RCPT_FILE_NM, A.OK_CCD, DECODE((SELECT COUNT(*) FROM NIC64B WHERE SSPS_DL_CRT_DT=A.SSPS_DL_CRT_DT AND SSPS_DL_ID=A.SSPS_DL_ID),0,'No','Yes') AS FILE_ATT_YN, I.FIU_NO , I.FIU_REG_DT , G.GNL_AC_NO , G.ACNT_NO , G.MN_DL_DPRT_CD , NVL(G.MN_DL_DPRT_NM, (SELECT DPRT_NM FROM NIC41B Z WHERE DPRT_CD = G.MN_DL_DPRT_CD)) AS MN_DL_DPRT_NM , G.PRFT_BRN_CD , NVL(G.PRFT_BRN_NM, (SELECT DPRT_NM FROM NIC41B Z WHERE DPRT_CD = G.PRFT_BRN_CD)) AS PRFT_BRN_NM , A.TRIG_CTNT , A.XCL_RSN_CNTNT , I.SND_RCPT_DOC_NO , CASE WHEN LENGTH(I.RPR_OGN_CD) = 4 THEN '보기' WHEN COALESCE(A.KFU_RRPR_STS_CD, A.KFU_RPR_STS_CD, A.RPR_PRGRS_CCD) IN ('10','40','50') THEN '보기' ELSE '수정' END AS XML_FILE_EDIT , TO_CHAR(A.KFU_RPR_DT, 'YYYYMMDD') AS KFU_RPR_DT , NVL(A.KFU_RPR_STS_CD, A.RPR_PRGRS_CCD) AS KFU_RPR_STS_CD , GET_CODE_NAME('S060', NVL(A.KFU_RPR_STS_CD, A.RPR_PRGRS_CCD)) AS KFU_RPR_STS_NM , A.KFU_RRPR_STS_CD , GET_CODE_NAME('S060', A.KFU_RRPR_STS_CD) AS KFU_RRPR_STS_NM , NVL(A.RRPR_YN, 'N') AS RRPR_YN , COALESCE(A.KFU_RRPR_STS_CD, A.KFU_RPR_STS_CD, A.RPR_PRGRS_CCD) AS ALL_RPR_STS_CD , GET_CODE_NAME('S060', COALESCE(A.KFU_RRPR_STS_CD, A.KFU_RPR_STS_CD, A.RPR_PRGRS_CCD)) AS ALL_RPR_STS_NM , I.RPR_OGN_CD , (SELECT SUBSTR(MAX(RPR_P_DY_TM),1,8) FROM NIC66B_W WHERE INST_ID = A.INST_ID ) AS INST_DT , (SELECT MAX(SND_RCPT_DOC_NO) KEEP (DENSE_RANK FIRST ORDER BY RRPR_SQ, SQ) FROM NIC80B_HIS WHERE SSPS_DL_CRT_DT = A.SSPS_DL_CRT_DT AND SSPS_DL_ID = A.SSPS_DL_ID AND KFU_RPR_STS_CD = '10' AND ( (SND_RCPT_DOC_NO = I.SND_RCPT_DOC_NO AND A.KFU_RPR_STS_CD IN ('34','44','54')) OR SND_RCPT_DOC_NO != I.SND_RCPT_DOC_NO ) ) AS INIT_DOC_NO --최초문서번호 FROM NIC66B A, NIC70B B, NIC35B H, NIC80B I, (SELECT SSPS_DL_CRT_DT , SSPS_DL_ID , GNL_AC_NO , MN_DL_DPRT_CD , MN_DL_DPRT_NM , PRFT_BRN_CD , PRFT_BRN_NM , ACNT_NO FROM NIC71B WHERE (SSPS_DL_CRT_DT, SSPS_DL_ID, GNL_AC_NO) IN (SELECT X.SSPS_DL_CRT_DT, X.SSPS_DL_ID, MIN(X.GNL_AC_NO) FROM NIC71B X , NIC66B Y WHERE X.SSPS_DL_CRT_DT = Y.SSPS_DL_CRT_DT AND X.SSPS_DL_ID = Y.SSPS_DL_ID AND X.RNMCNO = Y.DL_P_RNMCNO GROUP BY X.SSPS_DL_CRT_DT, X.SSPS_DL_ID) ) G WHERE A.SSPS_DL_CRT_DT = B.SSPS_DL_CRT_DT(+) AND A.DL_P_RNMCNO = B.DL_P_RNMCNO(+) AND A.DL_P_RNMCNO = H.RNMCNO (+) AND A.SSPS_DL_CRT_DT = I.SSPS_DL_CRT_DT(+) AND A.SSPS_DL_ID = I.SSPS_DL_ID(+) AND A.SSPS_DL_CRT_DT = G.SSPS_DL_CRT_DT(+) AND A.SSPS_DL_ID = G.SSPS_DL_ID(+) AND A.SSPS_DL_CRT_CCD IN ( 'STR', 'KYC') ) A WHERE 1=1
AND A.SSPS_DL_CRT_DT BETWEEN #{startDate} AND #{endDate}
AND A.KFU_RPR_DT BETWEEN #{startDate} AND #{endDate}
AND #{branchCode} IN (SELECT MN_DL_BRN_CD FROM NIC73B WHERE SSPS_DL_CRT_DT = A.SSPS_DL_CRT_DT AND SSPS_DL_ID = A.SSPS_DL_ID)
AND OK_CCD = #{OK_CCD}
AND UPPER(DL_P_NM) like '%'||UPPER(#{CS_NM})||'%'
AND CS_NO = #{CS_NO}
AND A.DL_P_RNMCNO = (SELECT RNMCNO FROM NIC17B WHERE ACNT_NO LIKE #{ACNT_NO} || '%')
AND COALESCE(A.KFU_RRPR_STS_CD, A.KFU_RPR_STS_CD, A.RPR_PRGRS_CCD) = #{RPR_PRGRS_CCD}
AND A.RPR_PRGRS_CCD IN ('9', '99', '98')
AND A.SSPS_DL_CRT_CCD = #{SSPS_DL_CRT_CCD}
AND A.SSPS_DL_CRT_CCD IN ('STR', 'KYC')
AND (1 = #{SSPS_TYP_CD_YN} OR A.SSPS_TYP_CD = #{SSPS_TYP_CD}) ORDER BY SSPS_DL_CRT_DT DESC, SSPS_DL_ID ) X

SELECT NVL(MAX(SQ), 0) + 1 AS MAX_FILE_SQ 
  FROM NIC80B
 WHERE CTR_STR_CCD = #{CTR_STR_CCD}
   AND RPR_YR = #{RPR_YR}
   AND RPR_DT = #{RPR_DT}

SELECT /* 문서시작 */ 'CTRSTART' AS CTR00, --문서시작 A.RPR_CCD AS CTR01, --메시지타입
/* 표제부에 관한 정보 */ TRIM(A.RPR_DOC_NO_DL_YR||'-'||LPAD(A.RPR_DOC_NO_FNL_SQ,8,'0')) AS CTR02, --2 문서번호(YYYY TO_CHAR(SYSDATE,'YYYYMMDD') AS CTR03, --3 보고일자 CASE WHEN A.RPR_CCD NOT IN ('01','99') THEN TRIM(B.RPR_DOC_NO_DL_YR||'-'||LPAD(B.RPR_DOC_NO_FNL_SQ,8,'0')) ELSE '' END AS CTR04, --4 종전문서번호 LPAD(A.RNM_PR_DL_SQ,7,'0') || '/'|| ( SELECT LPAD(COUNT(*),7,'0') FROM NIC66B WHERE SSPS_DL_CRT_DT = A.SSPS_DL_CRT_DT AND DL_P_RNMCNO = A.DL_P_RNMCNO AND SSPS_DL_CRT_CCD = A.SSPS_DL_CRT_CCD AND OK_CCD != 2 ) AS CTR05, --5 거래순번 TRIM(A.DOC_NO_YR||'-'||LPAD(A.DOC_SQ,8,'0')) AS CTR06, --6 기본문서번호
/* I. 보고기관에 관한 정보 */ Z.RPR_OGN_NM AS CTR07,--7 보고기관명 Z.TRNS_OGN_CD_NEW AS CTR08,--8 보고기관코드 Z.RPR_RSPSB_P_NM AS CTR09,--9 보고책임자명 Z.RPR_CHRG_P_NM AS CTR10,--10 보고담당자명 Z.RPR_CHRG_P_TEL_NO AS CTR11,--11 보고담당자전화번호
/* II 거래자에 관한 정보 */ /* II-1 공통사항 */ --12,13,14항목을 반드시 기입하되, 단 20번항목이 기입될 경우 13,14항목 선택항목 C.DL_P_NM AS CTR12,--12 거래자명 C.DL_P_RNM_NO_CCD AS CTR13,--13 거래자실명번호구분 C.CS_NO AS CTR14,--14 거래자실명번호 C.DL_P_NTNLT_CD AS CTR15,--15 거래자국적코드 GET_CODE_NAME('M004',C.DL_P_NTNLT_CD) AS CTR16,--16 거래자국적명
/* II-2 개인인 경우 */ --(13번 거래자 실명번호 구분 중 주민등록번호(개인),외국인등록번호, 여권번호,국내거소신고번호, 기타일경우 기입) --(20번 실명조합번호는 15번 국적에서 코드가 KR이 아닐 경우 기입) CASE WHEN C.DL_P_RNM_NO_CCD IN ('02','03','05','08','09','11','12','99') THEN '' ELSE NVL(TRIM(D.DL_P_HSE_PST_NO), TRIM(D.DL_P_WP_PST_NO)) END AS CTR17,--17 거래자우편번호 CASE WHEN C.DL_P_RNM_NO_CCD IN ('02','03','05','08','09','11','12','99') THEN '' ELSE NVL(TRIM(D.DL_P_HSE_BSC_ADDR), D.DL_P_WP_BSC_ADDR) END AS CTR18_1,--18 거래자주소(기본주소) CASE WHEN C.DL_P_RNM_NO_CCD IN ('02','03','05','08','09','11','12','99') THEN '' ELSE NVL(TRIM(D.DL_P_HSE_DNG_ADDR), D.DL_P_WP_DNG_ADDR) END AS CTR18_2,--18 거래자주소(동이하주소) D.DL_P_BRTDY AS CTR19,--19 거래자생년월일 DECODE(D.DL_P_SEX_CD,'1','3','3','3','2','4','4','4') AS CTR20,--20 성별 CASE WHEN C.DL_P_RNM_NO_CCD IN ('02','03','05','08','09','11','12','99') THEN '' ELSE D.DL_P_HSE_NATI END AS CTR21_1_1, --21 거래자자택국가번호 CASE WHEN C.DL_P_RNM_NO_CCD IN ('02','03','05','08','09','11','12','99') THEN '' ELSE D.DL_P_HSE_AREA END AS CTR21_1_2, --21 거래자자택지역번호 CASE WHEN C.DL_P_RNM_NO_CCD IN ('02','03','05','08','09','11','12','99') THEN '' ELSE D.DL_P_HSE_ECNO END AS CTR21_1_3, --21 거래자자택국번 CASE WHEN C.DL_P_RNM_NO_CCD IN ('02','03','05','08','09','11','12','99') THEN '' ELSE D.DL_P_HSE_NO END AS CTR21_1_4, --21 거래자자택번호 CASE WHEN C.DL_P_RNM_NO_CCD IN ('02','03','05','08','09','11','12','99') THEN '' ELSE D.DL_P_MBL_NATI END AS CTR21_2_1, --21 거래자핸드폰번호 CASE WHEN C.DL_P_RNM_NO_CCD IN ('02','03','05','08','09','11','12','99') THEN '' ELSE D.DL_P_MBL_AREA END AS CTR21_2_2, --21 거래자핸드폰번호 CASE WHEN C.DL_P_RNM_NO_CCD IN ('02','03','05','08','09','11','12','99') THEN '' ELSE D.DL_P_MBL_ECNO END AS CTR21_2_3, --21 거래자핸드폰번호 CASE WHEN C.DL_P_RNM_NO_CCD IN ('02','03','05','08','09','11','12','99') THEN '' ELSE D.DL_P_MBL_NO END AS CTR21_2_4, --21 거래자핸드폰번호 --NVL(D.DL_P_HSE_TEL_NO,D.DL_P_MBL_TEL_NO) AS CTR21,--21 거래자전화번호 CASE WHEN C.DL_P_NTNLT_CD='KR' THEN D.RNM_CMBNTN_NO ELSE C.CS_NO END AS CTR22,--22 실명조합번호 D.DL_P_PSPT_NO AS CTR23,--23 여권번호 CASE WHEN C.DL_P_RNM_NO_CCD IN ('02','03','05','08','09','11','12','99') THEN '' ELSE --법인일 경우 ''처리 D.OCPTN_CCD END AS CTR24,--24 거래자직업구분 CASE WHEN TRIM(D.WP_NM) NOT IN ('A999999','test') THEN TRIM(D.WP_NM) END AS CTR25,--25 거래자직장(회사)명 D.IND_TYP_CD AS CTR26,--26 거래자직장업종코드 '' AS CTR27,--27 거래자직장사업자번호
/* II-3 법인인 경우 */ --13번 거래자 실명번호 구분 중 주민등록번호(기타단체), 사업자등록번호, 투자등록번호, 고유번호/납세번호, 기타일 경우 기입되며, 모두 선택기재사항 E.RPRST_P_NM1 AS CTR28,--28 대표자명 ---------20201103 백승록 추가-------------------------------- --CASE WHEN TRIM(E.RPRST_P_BRDY1) IS NOT NULL THEN '99' ELSE '' END AS CTR29,--29 대표자실명번호구분
CASE WHEN C.DL_P_RNM_NO_CCD IN ('02','03','05','08','09','11','12','99') THEN '99' END AS CTR29,--29 대표자실명번호구분
--TRIM(E.RPRST_P_BRDY1) AS CTR30,--30 대표자실명번호 --'' AS CTR30,--30 대표자실명번호
CASE WHEN C.DL_P_RNM_NO_CCD IN ('02','03','05','08','09','11','12','99') THEN CASE WHEN TRIM(E.RPRST_P_BRDY1) IS NOT NULL THEN SUBSTR(E.RPRST_P_BRDY1,3,8)||'0000000' ELSE '0000000000000' END END AS CTR30,--30 대표자실명번호 ---------------------------------------------------------- E.RPRST_P_NTNLT_CD1 AS CTR31,--31 대표자국적코드 GET_CODE_NAME('M004',E.RPRST_P_NTNLT_CD1) AS CTR32,--32 대표자국적명 --TRIM(E.BSNSG_FNDTN_DT) AS CTR33,--33 사업체설립일 --DECODE(TRIM(E.BSNSG_FNDTN_DT),'',F.AC_OPN_DT) AS CTR33,--33 사업체설립일 CASE WHEN C.DL_P_RNM_NO_CCD IN ('02','03','05','08','09','11','12','99') THEN DECODE(TRIM(E.BSNSG_FNDTN_DT),'',F.AC_OPN_DT,TRIM(E.BSNSG_FNDTN_DT)) ELSE '' END AS CTR33,--33 사업체설립일 CASE WHEN C.DL_P_RNM_NO_CCD IN ('02','03','05','08','09','11','12','99') THEN DECODE(TRIM(E.IND_TYP_CD),'','94990',TRIM(E.IND_TYP_CD)) ELSE E.IND_TYP_CD END AS CTR34,--34 업종코드 E.CORP_RGST_NO AS CTR35,--35 법인등록번호 CASE WHEN C.DL_P_RNM_NO_CCD IN ('02','03','05','08','09','11','12','99') THEN TRIM(E.HD_BRNCH_PST_NO) ELSE '' END AS CTR36, --36 사업체본점우편번호 CASE WHEN C.DL_P_RNM_NO_CCD IN ('02','03','05','08','09','11','12','99') THEN TRIM(E.BSNS_CMPNY_PST_NO) ELSE '' END AS CTR37, --37 사업체사업장우편번호 CASE WHEN C.DL_P_RNM_NO_CCD IN ('02','03','05','08','09','11','12','99') THEN E.HD_BRNCH_BSC_ADDR ELSE '' END AS CTR38_1,--38 사업체본점주소 CASE WHEN C.DL_P_RNM_NO_CCD IN ('02','03','05','08','09','11','12','99') THEN E.HD_BRNCH_DNG_ADDR ELSE '' END AS CTR38_2,--38 사업체본점주소 CASE WHEN C.DL_P_RNM_NO_CCD IN ('02','03','05','08','09','11','12','99') THEN E.BSNS_CMPNY_BSC_ADDR ELSE '' END AS CTR39_1,--39 사업체사업장주소 CASE WHEN C.DL_P_RNM_NO_CCD IN ('02','03','05','08','09','11','12','99') THEN E.BSNS_CMPNY_DNG_ADDR ELSE '' END AS CTR39_2,--39 사업체사업장주소 CASE WHEN C.DL_P_RNM_NO_CCD IN ('02','03','05','08','09','11','12','99') THEN E.HD_BRNCH_NATI ELSE '' END AS CTR40_1, -- 40 사업체본점국가번호 CASE WHEN C.DL_P_RNM_NO_CCD IN ('02','03','05','08','09','11','12','99') THEN E.HD_BRNCH_AREA ELSE '' END AS CTR40_2, -- 40 사업체본점지역번호 CASE WHEN C.DL_P_RNM_NO_CCD IN ('02','03','05','08','09','11','12','99') THEN E.HD_BRNCH_ECNO ELSE '' END AS CTR40_3, -- 40 사업체본점국번 CASE WHEN C.DL_P_RNM_NO_CCD IN ('02','03','05','08','09','11','12','99') THEN E.HD_BRNCH_NO ELSE '' END AS CTR40_4, -- 40 사업체본점번호 CASE WHEN C.DL_P_RNM_NO_CCD IN ('02','03','05','08','09','11','12','99') THEN E.BSNS_CMPNY_NATI ELSE '' END AS CTR41_1, -- 41 사업체사업장국가번호 CASE WHEN C.DL_P_RNM_NO_CCD IN ('02','03','05','08','09','11','12','99') THEN E.BSNS_CMPNY_AREA ELSE '' END AS CTR41_2, -- 41 사업체사업장지역번호 CASE WHEN C.DL_P_RNM_NO_CCD IN ('02','03','05','08','09','11','12','99') THEN E.BSNS_CMPNY_ECNO ELSE '' END AS CTR41_3, -- 41 사업체사업장국번 CASE WHEN C.DL_P_RNM_NO_CCD IN ('02','03','05','08','09','11','12','99') THEN E.BSNS_CMPNY_NO ELSE '' END AS CTR41_4, -- 41 사업체사업장번호 --E.HD_BRNCH_TEL_NO AS CTR40,--40 사업체본점전화번호 --E.BSNS_CMPNY_TEL_NO AS CTR41,--41 사업체사업장전화번호
/* III 현금거래 내역에 관한 정보 */ /* III-1 공통사항 */ --전체 필수항목 G.DL_DT||LPAD(DL_TM,6,'0') AS CTR42,--42 거래발생일시 G.HANDLNG_BRN_NM AS CTR43,--43 거래영업점명 TRIM(G.HANDLNG_BRN_PST_NO) AS CTR44,--44 거래영업점우편번호
G.DL_CHNNL_CD AS CTR45_TEMP,--45 거래채널 DECODE(G.DL_CHNNL_CD,'01','01','02','02','99') AS CTR45,--45 거래채널
'01' AS CTR46,--46 거래수단 G.CSH AS CTR47,--47 거래금액 G.CTR_DL_KND_CD AS CTR48,--48 거래종류 CASE WHEN TRIM(H.PRXY_NM) IS NOT NULL THEN '1' ELSE '2' END AS CTR49,--49 거래대리인존재여부 H.PRXY_NM AS CTR50,--50 거래대리인명 CASE WHEN TRIM(H.PRXY_NM) IS NOT NULL THEN H.PRXY_RNM_NO_CCD END AS CTR51,--51 거래대리인실명번호구분 COALESCE(H.PRXY_CS_NO, TRIM(N2.CS_NO)) AS CTR52,--52 거래대리인실명번호 COALESCE(H.PRXY_NATI, P2.CNTY_NATI_CRYP, Q2.CNTY_NATI_CRYP) AS CTR53_1,--53 거래대리인연락처국가번호 COALESCE(H.PRXY_AREA, P2.CNTY_AREA_CRYP, Q2.CNTY_AREA_CRYP) AS CTR53_2,--53 거래대리인연락처지역번호 COALESCE(H.PRXY_ECNO, P2.CNTY_ECNO_CRYP, Q2.CNTY_ECNO_CRYP) AS CTR53_3,--53 거래대리인연락처국번 COALESCE(H.PRXY_NO, P2.CNTY_NO_CRYP, Q2.CNTY_NO_CRYP) AS CTR53_4,--53 거래대리인연락처번호 --H.PRXY_TEL_NO AS CTR53,--53 거래대리인전화번호 CASE WHEN TRIM(H.PRXY_NM) IS NOT NULL THEN H.PRXY_NTNLT_CD END AS CTR54,--54 거래대리인국적코드 CASE WHEN TRIM(H.PRXY_NM) IS NOT NULL THEN GET_CODE_NAME('M004',H.PRXY_NTNLT_CD) END AS CTR55,--55 거래대리인국적명
CASE WHEN TRIM(H.PRXY_NM) IS NOT NULL THEN NVL(TRIM(H.AC_OWN_P_RLTNS_KFU_CD),'99') END AS CTR56_TEMP,--56 거래대리인거래자와관계코드 CASE WHEN TRIM(H.PRXY_NM) IS NOT NULL THEN NVL(TRIM(H.AC_OWN_P_RLTNS_KFU_CD),'99') END AS CTR56,--56 거래대리인거래자와관계코드 CASE WHEN TRIM(H.PRXY_NM) IS NOT NULL THEN H.AC_OWN_P_RLTNS_KFU_NM END AS CTR57,--57 거래대리인거래자와 관계명
/* III-2 계좌거래의 경우 */ --선택사항이며, 35번 거래종류코드값이 11.계좌+지급,12계좌+영수 일 경우 모두 필수 CASE WHEN G.CTR_DL_KND_CD IN ('11','12') THEN L.ACNT_NO END AS CTR58,--58 관련계좌번호 CASE WHEN G.CTR_DL_KND_CD IN ('11','12') THEN NVL(TRIM(L.AC_OPN_BRN_NM), (SELECT DPRT_NM FROM SSQ.NIC41B WHERE DPRT_CD = L.OPN_BRN_CD)) END AS CTR59,--59 계좌개설점 CASE WHEN G.CTR_DL_KND_CD IN ('11','12') THEN NVL(TRIM(L.AC_OPN_BRN_PST_NO), (SELECT TRIM(DPRT_POST_NO) FROM SSQ.NIC41B WHERE DPRT_CD = L.OPN_BRN_CD)) END AS CTR60,--60 계좌개설점우편번호 CASE WHEN G.CTR_DL_KND_CD IN ('11','12') THEN L.AC_OPN_DT END AS CTR61,--61 계좌개설일 CASE WHEN G.CTR_DL_KND_CD NOT IN ('11','12') THEN '' WHEN L.AC_OPN_PRXY_F IS NOT NULL THEN L.AC_OPN_PRXY_F END AS CTR62,--62 계좌대리인존재여부 CASE WHEN G.CTR_DL_KND_CD NOT IN ('11','12') THEN '' WHEN L.AC_OPN_PRXY_F = '1' THEN I.PRXY_NM END AS CTR63,--63 계좌대리인명 CASE WHEN G.CTR_DL_KND_CD NOT IN ('11','12') THEN '' WHEN L.AC_OPN_PRXY_F = '1' THEN NVL(I.PRXY_RNM_NO_CCD, '99') END AS CTR64,--64 계좌대리인실명번호구분 CASE WHEN G.CTR_DL_KND_CD NOT IN ('11','12') THEN '' WHEN L.AC_OPN_PRXY_F = '1' THEN I.PRXY_CS_NO END AS CTR65,--65 계좌대리인실명번호 CASE WHEN G.CTR_DL_KND_CD NOT IN ('11','12') THEN '' WHEN L.AC_OPN_PRXY_F = '1' AND I.PRXY_CS_NO IS NOT NULL THEN '0' END AS CTR65_1,--65 계좌대리인실명번호 CASE WHEN G.CTR_DL_KND_CD NOT IN ('11','12') THEN '' WHEN L.AC_OPN_PRXY_F = '1' THEN I.PRXY_CNTY_NATI_CRYP END AS CTR66_1,--66 계좌대리인연락처국가번호 CASE WHEN G.CTR_DL_KND_CD NOT IN ('11','12') THEN '' WHEN L.AC_OPN_PRXY_F = '1' THEN I.PRXY_CNTY_AREA_CRYP END AS CTR66_2,--66 계좌대리인연락처지역번호 CASE WHEN G.CTR_DL_KND_CD NOT IN ('11','12') THEN '' WHEN L.AC_OPN_PRXY_F = '1' THEN I.PRXY_CNTY_ECNO_CRYP END AS CTR66_3,--66 계좌대리인연락처국번 CASE WHEN G.CTR_DL_KND_CD NOT IN ('11','12') THEN '' WHEN L.AC_OPN_PRXY_F = '1' THEN I.PRXY_CNTY_NO_CRYP END AS CTR66_4,--66 계좌대리인연락처번호 CASE WHEN G.CTR_DL_KND_CD NOT IN ('11','12') THEN '' WHEN L.AC_OPN_PRXY_F = '1' THEN NVL(I.PRXY_NTNLT_CD, 'KR') END AS CTR67,--67 계좌대리인국적코드 CASE WHEN G.CTR_DL_KND_CD NOT IN ('11','12') THEN '' WHEN L.AC_OPN_PRXY_F = '1' THEN GET_CODE_NAME('M004', NVL(I.PRXY_NTNLT_CD, 'KR')) END AS CTR68,--68 계좌대리인국적명 CASE WHEN G.CTR_DL_KND_CD NOT IN ('11','12') THEN '' WHEN L.AC_OPN_PRXY_F = '1' THEN I.AC_OWN_P_RLTNS_KFU_CD END AS CTR69_TEMP,--69 계좌대리인관계코드 CASE WHEN G.CTR_DL_KND_CD NOT IN ('11','12') THEN '' WHEN L.AC_OPN_PRXY_F = '1' THEN I.AC_OWN_P_RLTNS_KFU_CD END AS CTR69,--69 계좌대리인관계코드 CASE WHEN G.CTR_DL_KND_CD NOT IN ('11','12') THEN '' WHEN L.AC_OPN_PRXY_F = '1' THEN I.AC_OWN_P_RLTNS_KFU_NM END AS CTR70,--70 계좌대리인관계명
/* III-3 유가증권거래의 경우 */ --선택사항이며, 35번 거래종류코드값이 25.비계좌(유가증권)+지급, 26.비계좌(유가증권)+영수일경우 모두필수이나, --40. 관련유가증권종류 코드값이 11.선불카드일 경우 33,33-1 선택항목 J.CHCK_KND_CD AS CTR71,--71 관련유가증권종류 J.CHCK_STRT_NO AS CTR72,--72 관련유가증권시작번호 J.CHCK_END_NO AS CTR73,--73 관련유가증권끝번호
/* III-4 자기앞수표거래의 경우 */ --40번 유가증권종류에서 코드값이 05.자기앞수표일경우 필수 항목 J.BNK_NM AS CTR74,--74 현금지급은행명 J.BNK_CD AS CTR75,--75 현금지급은행기관코드 J.BRN_NM AS CTR76,--76 현금지급영업점명 TRIM(J.BRN_PST_NO) AS CTR77,--77 현금지급영업점우편번호
/* IV 수취인 계좌에 관한 정보 */ --35번 거래종류항목코드 중 22.비계좌(송금)+영수일 경우 필수 항목 K.CPRTY_TRSNS_AC_NO AS CTR78,--78 수취인계좌번호 K.CPRTY_TRSNS_FOGN_NM AS CTR79,--79 수취금융기관명 K.CPRTY_TRSNS_OGN_CD AS CTR80,--80 수취금융기관코드 K.CPRTY_TRSNS_AC_NM AS CTR81,--81 수취인성명
/* 취소 또는 정정 보고에 관한 정보 */ --선택사항이며, 01번 메시지 타입 코드값이 02,03,97,98일경우 필수 항목 CASE WHEN A.RPR_CCD NOT IN ('01','93') THEN A.CAC_UPD_RSN_CNTNT END AS CTR82, 'CTREND' AS CTR83,
A.DL_P_RNMCNO, G.GNL_AC_NO, G.GDS_NO, G.DL_DT, G.DL_SQ, I.PRXY_RNMCNO AS CTR65_RNMCNO, H.PRXY_RNMCNO AS CTR52_RNMCNO
FROM NIC66B A, NIC84B B, NIC70B C, NIC78B D, NIC79B E,
NIC71B F, NIC75B G, NIC98B H, NIC72B I,
( SELECT B.SSPS_DL_CRT_DT, B.SSPS_DL_ID, B.GNL_AC_NO, B.GDS_NO, B.DL_DT, B.DL_SQ, C.CHCK_KND_CD, C.CHCK_STRT_NO, C.CHCK_END_NO, DECODE(C.CHCK_KND_CD, '05', Z.RPR_OGN_NM, '') AS BNK_NM, DECODE(C.CHCK_KND_CD, '05', Z.TRNS_OGN_CD_NEW, '') AS BNK_CD, DECODE(C.CHCK_KND_CD, '05', B.HANDLNG_BRN_NM, '') AS BRN_NM, DECODE(C.CHCK_KND_CD, '05', B.HANDLNG_BRN_PST_NO, '') AS BRN_PST_NO FROM NIC71B A, NIC75B B, NIC76B C, NIC86B Z WHERE A.SSPS_DL_CRT_DT = B.SSPS_DL_CRT_DT AND A.SSPS_DL_ID = B.SSPS_DL_ID AND A.GNL_AC_NO = B.GNL_AC_NO AND B.SSPS_DL_CRT_DT = C.SSPS_DL_CRT_DT(+) AND B.SSPS_DL_ID = C.SSPS_DL_ID(+) AND B.GNL_AC_NO = C.GNL_AC_NO(+) AND B.DL_DT = C.DL_DT(+) AND B.DL_SQ = C.DL_SQ(+) AND B.CTR_DL_KND_CD IN ('25','26') AND A.SSPS_DL_CRT_DT = #{SSPS_DL_CRT_DT} AND A.SSPS_DL_ID = #{SSPS_DL_ID} ) J,--수표정보 ( SELECT B.SSPS_DL_CRT_DT, B.SSPS_DL_ID, B.GNL_AC_NO, B.GDS_NO, B.DL_DT, B.DL_SQ, NVL(C.RLTV_FNC_ACNT_NO_CRYP,A.ACNT_NO) AS CPRTY_TRSNS_AC_NO, NVL(C.RLBK_NAME,Z.RPR_OGN_NM) AS CPRTY_TRSNS_FOGN_NM, NVL((SELECT TRIM(TRNSFRM_CD) FROM SSQ.NIC95B WHERE CD='L188' AND CD_VL9 = NVL(C.RLBK_CODE,'240')), 'ZZZZZZ') AS CPRTY_TRSNS_OGN_CD, NVL(C.RLTV_BANK_ACNT_NAME,A.CS_NM) AS CPRTY_TRSNS_AC_NM FROM NIC71B A, NIC75B B, NIC61B_CTR C, NIC86B Z WHERE A.SSPS_DL_CRT_DT = B.SSPS_DL_CRT_DT AND A.SSPS_DL_ID = B.SSPS_DL_ID AND A.GNL_AC_NO = B.GNL_AC_NO --AND B.SSPS_DL_CRT_DT = C.SSPS_DL_CRT_DT(+) --AND B.SSPS_DL_ID = C.SSPS_DL_ID(+) AND B.GNL_AC_NO = C.GNL_AC_NO(+) AND B.DL_DT = C.DL_DT(+) AND B.DL_SQ = C.DL_SQ(+) AND B.CTR_DL_KND_CD IN ('21','22') AND A.SSPS_DL_CRT_DT = #{SSPS_DL_CRT_DT} AND A.SSPS_DL_ID = #{SSPS_DL_ID} ) K,
( SELECT A.* FROM NIC71B A, NIC75B B WHERE 1 = 1 AND A.SSPS_DL_CRT_DT = B.SSPS_DL_CRT_DT AND A.SSPS_DL_ID = B.SSPS_DL_ID AND A.GNL_AC_NO = B.GNL_AC_NO AND B.CTR_DL_KND_CD IN ('11','12') AND B.SSPS_DL_CRT_DT = #{SSPS_DL_CRT_DT} AND B.SSPS_DL_ID = #{SSPS_DL_ID} ) L, NIC01B N, NIC04B P, NIC04B Q, SID.IDO_A_UUE_CLIENT_ENTY_ALIAS S, ( SELECT MAX(A.CDD_TAGT_ENTY_ID) AS CDD_TAGT_ENTY_ID , MIN(NVL(B.AREA_CODE_CRYP, C.MOBL_PHON_IDNF_NO_CRYP)) KEEP (DENSE_RANK FIRST ORDER BY CDD_CNTT_ADDR_TAGT_CODE, CDD_CNTT_ADDR_SECT_CODE DESC) AS NO_1 , MAX(NVL(B.PHON_ECNO_CRYP, C.MOBL_PHON_ECNO_CRYP)) KEEP (DENSE_RANK FIRST ORDER BY CDD_CNTT_ADDR_TAGT_CODE, CDD_CNTT_ADDR_SECT_CODE DESC) AS NO_2 , MAX(NVL(B.PHON_NO_CRYP, C.MOBL_PHON_NO_CRYP)) KEEP (DENSE_RANK FIRST ORDER BY CDD_CNTT_ADDR_TAGT_CODE, CDD_CNTT_ADDR_SECT_CODE DESC) AS NO_3 FROM SID.IDO_A_MAH_CDD_CNTT_ADDR_IF A , SID.IDO_A_UUE_PHONE B , SID.IDO_A_UUE_MOBILE C WHERE A.CDD_CNTT_ADDR_SECT_CODE IN ('TEL', 'MOB') AND A.CNTT_ADDR_ID = B.CNTT_ADDR_ID(+) AND A.CNTT_ADDR_ID = C.CNTT_ADDR_ID(+) AND A.CDD_TAGT_ENTY_ID = (SELECT PRXY_RNMCNO FROM NIC72B WHERE SSPS_DL_CRT_DT = #{SSPS_DL_CRT_DT} AND SSPS_DL_ID = #{SSPS_DL_ID} AND ROWNUM = 1) ) T, --SID.IDO_A_MAA_CLIENT_ACNT_DTLS R, SSQ.NIC01B N2, SSQ.NIC04B P2, SSQ.NIC04B Q2, NIC86B Z WHERE A.SSPS_DL_CRT_DT = B.SSPS_DL_CRT_DT(+) AND A.SSPS_DL_ID = B.SSPS_DL_ID(+)
AND A.SSPS_DL_CRT_DT = C.SSPS_DL_CRT_DT AND A.DL_P_RNMCNO = C.DL_P_RNMCNO
AND C.SSPS_DL_CRT_DT = D.SSPS_DL_CRT_DT(+) AND C.DL_P_RNMCNO = D.DL_P_RNMCNO(+) AND C.SSPS_DL_CRT_DT = E.SSPS_DL_CRT_DT(+) AND C.DL_P_RNMCNO = E.DL_P_RNMCNO(+)
AND A.SSPS_DL_CRT_DT = F.SSPS_DL_CRT_DT AND A.SSPS_DL_ID = F.SSPS_DL_ID
AND F.SSPS_DL_CRT_DT = G.SSPS_DL_CRT_DT AND F.SSPS_DL_ID = G.SSPS_DL_ID AND F.GNL_AC_NO = G.GNL_AC_NO
--AND F.SSPS_DL_CRT_DT = L.SSPS_DL_CRT_DT(+) --AND F.SSPS_DL_ID = L.SSPS_DL_ID(+) AND F.GNL_AC_NO = L.GNL_AC_NO(+)
AND G.SSPS_DL_CRT_DT = H.SSPS_DL_CRT_DT(+) AND G.SSPS_DL_ID = H.SSPS_DL_ID(+) AND G.GNL_AC_NO = H.GNL_AC_NO(+) AND G.DL_DT = H.DL_DT(+) AND G.DL_SQ = H.DL_SQ(+)
AND F.SSPS_DL_CRT_DT = I.SSPS_DL_CRT_DT(+) AND F.SSPS_DL_ID = I.SSPS_DL_ID(+) AND F.GNL_AC_NO = I.GNL_AC_NO(+)
AND G.SSPS_DL_CRT_DT = J.SSPS_DL_CRT_DT(+) AND G.SSPS_DL_ID = J.SSPS_DL_ID(+) AND G.GNL_AC_NO = J.GNL_AC_NO(+) AND G.DL_DT = J.DL_DT(+) AND G.DL_SQ = J.DL_SQ(+)
AND G.SSPS_DL_CRT_DT = K.SSPS_DL_CRT_DT(+) AND G.SSPS_DL_ID = K.SSPS_DL_ID(+) AND G.GNL_AC_NO = K.GNL_AC_NO(+) AND G.DL_DT = K.DL_DT(+) AND G.DL_SQ = K.DL_SQ(+)
AND I.PRXY_RNMCNO = N.RNMCNO(+) AND I.PRXY_RNMCNO = P.RNMCNO(+) AND P.CNTC_TYP_CD(+) = '3' AND I.PRXY_RNMCNO = Q.RNMCNO(+) AND Q.CNTC_TYP_CD(+) = '1' AND I.PRXY_RNMCNO = S.ENTY_ID(+) AND I.PRXY_RNMCNO = T.CDD_TAGT_ENTY_ID(+)
--AND G.GNL_AC_NO = R.ACNT_ID(+) --AND R.ACNT_AGNT_CODE(+) != '1' --AND R.AGNT_ENTY_ID(+) = 0
AND H.PRXY_RNMCNO = N2.RNMCNO(+) AND H.PRXY_RNMCNO = P2.RNMCNO(+) AND P2.CNTC_TYP_CD(+) = '3' AND H.PRXY_RNMCNO = Q2.RNMCNO(+) AND Q2.CNTC_TYP_CD(+) = '1'
AND A.SSPS_DL_CRT_DT = #{SSPS_DL_CRT_DT} AND A.SSPS_DL_ID = #{SSPS_DL_ID}

SELECT /* 문서시작 */ 'CTRSTART' AS CTR00, --문서시작 A.RPR_CCD AS CTR01, --메시지타입
/* 표제부에 관한 정보 */ TRIM(A.RPR_DOC_NO_DL_YR||'-'||LPAD(A.RPR_DOC_NO_FNL_SQ,8,'0')) AS CTR02, --2 문서번호(YYYY TO_CHAR(SYSDATE,'YYYYMMDD') AS CTR03, --3 보고일자 CASE WHEN A.RPR_CCD NOT IN ('01','99') THEN TRIM(B.RPR_DOC_NO_DL_YR||'-'||LPAD(B.RPR_DOC_NO_FNL_SQ,8,'0')) ELSE '' END AS CTR04, --4 종전문서번호 LPAD(A.RNM_PR_DL_SQ,7,'0') || '/'|| ( SELECT LPAD(COUNT(*),7,'0') FROM NIC66B WHERE SSPS_DL_CRT_DT = A.SSPS_DL_CRT_DT AND DL_P_RNMCNO = A.DL_P_RNMCNO AND SSPS_DL_CRT_CCD = A.SSPS_DL_CRT_CCD AND OK_CCD != 2 ) AS CTR05, --5 거래순번 TRIM(A.RPR_DOC_NO_DL_YR||'-'||LPAD(A.DOC_SQ,8,'0')) AS CTR06, --6 기본문서번호
/* I. 보고기관에 관한 정보 */ Z.RPR_OGN_NM AS CTR07,--7 보고기관명 Z.TRNS_OGN_CD_NEW AS CTR08,--8 보고기관코드 Z.RPR_RSPSB_P_NM AS CTR09,--9 보고책임자명 Z.RPR_CHRG_P_NM AS CTR10,--10 보고담당자명 Z.RPR_CHRG_P_TEL_NO AS CTR11,--11 보고담당자전화번호
/* II 거래자에 관한 정보 */ /* II-1 공통사항 */ --12,13,14항목을 반드시 기입하되, 단 20번항목이 기입될 경우 13,14항목 선택항목 '' AS CTR12,--12 거래자명 '' AS CTR13,--13 거래자실명번호구분 '' AS CTR14,--14 거래자실명번호 '' AS CTR15,--15 거래자국적코드 '' AS CTR16,--16 거래자국적명
/* II-2 개인인 경우 */ --(13번 거래자 실명번호 구분 중 주민등록번호(개인),외국인등록번호, 여권번호,국내거소신고번호, 기타일경우 기입) --(20번 실명조합번호는 15번 국적에서 코드가 KR이 아닐 경우 기입) '' AS CTR17,--17 거래자우편번호 '' AS CTR18,--18 거래자주소 '' AS CTR19,--19 거래자생년월일 '' AS CTR20,--20 성별 '' AS CTR21,--21 거래자전화번호 '' AS CTR22,--22 실명조합번호 '' AS CTR23,--23 여권번호 '' AS CTR24,--24 거래자직업구분 '' AS CTR25,--25 거래자직장(회사)명 '' AS CTR26,--26 거래자직장업종코드 '' AS CTR27,--27 거래자직장사업자번호
/* II-3 법인인 경우 */ --13번 거래자 실명번호 구분 중 주민등록번호(기타단체), 사업자등록번호, 투자등록번호, 고유번호/납세번호, 기타일 경우 기입되며, 모두 선택기재사항 '' AS CTR28,--28 대표자명 '' AS CTR29,--29 대표자실명번호구분 '' AS CTR30,--30 대표자실명번호 '' AS CTR31,--31 대표자국적코드 '' AS CTR32,--32 대표자국적명 '' AS CTR33,--33 사업체설립일 '' AS CTR34,--34 업종코드 '' AS CTR35,--35 법인등록번호 '' AS CTR36,--36 사업체본점우편번호 '' AS CTR37,--37 사업체사업장우편번호 '' AS CTR38,--38 사업체본점주소 '' AS CTR39,--39 사업체사업장주소 '' AS CTR40,--40 사업체본점전화번호 '' AS CTR41,--41 사업체사업장전화번호
/* III 현금거래 내역에 관한 정보 */ /* III-1 공통사항 */ --전체 필수항목 '' AS CTR42,--42 거래발생일시 '' AS CTR43,--43 거래영업점명 '' AS CTR44,--44 거래영업점우편번호
'' AS CTR45_TEMP,--45 거래채널 '' AS CTR45,--45 거래채널
'' AS CTR46,--46 거래수단 '' AS CTR47,--47 거래금액 '' AS CTR48,--48 거래종류 '' AS CTR49,--49 거래대리인존재여부 '' AS CTR50,--50 거래대리인명 '' AS CTR51,--51 거래대리인실명번호구분 '' AS CTR52,--52 거래대리인실명번호 '' AS CTR53,--53 거래대리인전화번호 '' AS CTR54,--54 거래대리인국적코드 '' AS CTR55,--55 거래대리인국적명
'' AS CTR56_TEMP,--56 거래대리인거래자와관계코드 '' AS CTR56,--56 거래대리인거래자와관계코드
'' AS CTR57,--57 거래대리인거래자와 관계명
/* III-2 계좌거래의 경우 */ --선택사항이며, 35번 거래종류코드값이 11.계좌+지급,12계좌+영수 일 경우 모두 필수 '' AS CTR58,--58 관련계좌번호 '' AS CTR59,--59 계좌개설점 '' AS CTR60,--60 계좌개설점우편번호 '' AS CTR61,--61 계좌개설일 '' AS CTR62,--62 계좌대리인존재여부 '' AS CTR63,--63 계좌대리인명 '' AS CTR64,--64 계좌대리인실명번호구분 '' AS CTR65,--65 계좌대리인실명번호 '' AS CTR66,--66 계좌대리인전화번호 '' AS CTR67,--67 계좌대리인국적코드 '' AS CTR68,--68 계좌대리인국적명
'' AS CTR69_TEMP,--69 계좌대리인관계코드 '' AS CTR69,--69 계좌대리인관계코드
'' AS CTR70,--70 계좌대리인관계명
/* III-3 유가증권거래의 경우 */ --선택사항이며, 35번 거래종류코드값이 25.비계좌(유가증권)+지급, 26.비계좌(유가증권)+영수일경우 모두필수이나, --40. 관련유가증권종류 코드값이 11.선불카드일 경우 33,33-1 선택항목 '' AS CTR71,--71 관련유가증권종류 '' AS CTR72,--72 관련유가증권시작번호 '' AS CTR73,--73 관련유가증권끝번호
/* III-4 자기앞수표거래의 경우 */ --40번 유가증권종류에서 코드값이 05.자기앞수표일경우 필수 항목 '' AS CTR74,--74 현금지급은행명 '' AS CTR75,--75 현금지급은행기관코드 '' AS CTR76,--76 현금지급영업점명 '' AS CTR77,--77 현금지급영업점우편번호
/* IV 수취인 계좌에 관한 정보 */ --35번 거래종류항목코드 중 22.비계좌(송금)+영수일 경우 필수 항목 '' AS CTR78,--78 수취인계좌번호 '' AS CTR79,--79 수취금융기관명 '' AS CTR80,--80 수취금융기관코드 '' AS CTR81,--81 수취인성명
/* 취소 또는 정정 보고에 관한 정보 */ --선택사항이며, 01번 메시지 타입 코드값이 02,03,97,98일경우 필수 항목 CASE WHEN A.RPR_CCD NOT IN ('01','93') THEN ( SELECT CNTNT FROM NIC66B_W WHERE (INST_ID,WORK_ID) IN ( SELECT INST_ID,MIN(WORK_ID) FROM NIC66B_W WHERE INST_ID = A.INST_ID GROUP BY INST_ID ) ) ELSE '' END AS CTR82, 'CTREND' AS CTR83
FROM NIC66B A, NIC84B B, NIC70B C, NIC78B D, NIC79B E,
NIC71B F, NIC75B G, NIC98B H, NIC72B I,
( SELECT B.SSPS_DL_CRT_DT, B.SSPS_DL_ID, B.GNL_AC_NO, B.GDS_NO, B.DL_DT, B.DL_SQ, C.CHCK_KND_CD, C.CHCK_STRT_NO, C.CHCK_END_NO, DECODE(C.CHCK_KND_CD, '05', Z.RPR_OGN_NM, '') AS BNK_NM, DECODE(C.CHCK_KND_CD, '05', Z.TRNS_OGN_CD, '') AS BNK_CD, DECODE(C.CHCK_KND_CD, '05', B.HANDLNG_BRN_NM, '') AS BRN_NM, DECODE(C.CHCK_KND_CD, '05', B.HANDLNG_BRN_PST_NO, '') AS BRN_PST_NO FROM NIC71B A, NIC75B B, NIC76B C, NIC86B Z WHERE A.SSPS_DL_CRT_DT = B.SSPS_DL_CRT_DT AND A.SSPS_DL_ID = B.SSPS_DL_ID AND A.GNL_AC_NO = B.GNL_AC_NO AND B.SSPS_DL_CRT_DT = C.SSPS_DL_CRT_DT(+) AND B.SSPS_DL_ID = C.SSPS_DL_ID(+) AND B.GNL_AC_NO = C.GNL_AC_NO(+) AND B.DL_DT = C.DL_DT(+) AND B.DL_SQ = C.DL_SQ(+) AND B.CTR_DL_KND_CD IN ('25','26') AND A.SSPS_DL_CRT_DT = #{SSPS_DL_CRT_DT} AND A.SSPS_DL_ID = #{SSPS_DL_ID} ) J,--수표정보 ( SELECT B.SSPS_DL_CRT_DT, B.SSPS_DL_ID, B.GNL_AC_NO, B.GDS_NO, B.DL_DT, B.DL_SQ, NVL(C.CPRTY_TRSNS_AC_NO,A.GNL_AC_NO) AS CPRTY_TRSNS_AC_NO, NVL(C.CPRTY_TRSNS_FOGN_NM,Z.RPR_OGN_NM) AS CPRTY_TRSNS_FOGN_NM, NVL(C.CPRTY_TRSNS_OGN_CD,Z.TRNS_OGN_CD) AS CPRTY_TRSNS_OGN_CD, NVL(C.CPRTY_TRSNS_AC_NM,A.CS_NM) AS CPRTY_TRSNS_AC_NM FROM NIC71B A, NIC75B B, NIC83B C, NIC86B Z WHERE A.SSPS_DL_CRT_DT = B.SSPS_DL_CRT_DT AND A.SSPS_DL_ID = B.SSPS_DL_ID AND A.GNL_AC_NO = B.GNL_AC_NO AND B.SSPS_DL_CRT_DT = C.SSPS_DL_CRT_DT(+) AND B.SSPS_DL_ID = C.SSPS_DL_ID(+) AND B.GNL_AC_NO = C.GNL_AC_NO(+) AND B.DL_DT = C.DL_DT(+) AND B.DL_SQ = C.DL_SQ(+) AND B.CTR_DL_KND_CD IN ('21','22') AND A.SSPS_DL_CRT_DT = #{SSPS_DL_CRT_DT} AND A.SSPS_DL_ID = #{SSPS_DL_ID} ) K,
( SELECT A.* FROM NIC71B A, NIC75B B WHERE A.SSPS_DL_CRT_DT = B.SSPS_DL_CRT_DT AND A.SSPS_DL_ID = B.SSPS_DL_ID AND A.GNL_AC_NO = B.GNL_AC_NO AND B.CTR_DL_KND_CD IN ('11','12') AND A.SSPS_DL_CRT_DT = #{SSPS_DL_CRT_DT} AND A.SSPS_DL_ID = #{SSPS_DL_ID} ) L,
NIC03B M, NIC86B Z WHERE A.SSPS_DL_CRT_DT = B.SSPS_DL_CRT_DT(+) AND A.SSPS_DL_ID = B.SSPS_DL_ID(+)
AND A.SSPS_DL_CRT_DT = C.SSPS_DL_CRT_DT AND A.DL_P_RNMCNO = C.DL_P_RNMCNO
AND C.SSPS_DL_CRT_DT = D.SSPS_DL_CRT_DT(+) AND C.DL_P_RNMCNO = D.DL_P_RNMCNO(+) AND C.SSPS_DL_CRT_DT = E.SSPS_DL_CRT_DT(+) AND C.DL_P_RNMCNO = E.DL_P_RNMCNO(+)
AND C.DL_P_RNMCNO = M.RNMCNO(+)
AND A.SSPS_DL_CRT_DT = F.SSPS_DL_CRT_DT AND A.SSPS_DL_ID = F.SSPS_DL_ID
AND F.SSPS_DL_CRT_DT = G.SSPS_DL_CRT_DT AND F.SSPS_DL_ID = G.SSPS_DL_ID AND F.GNL_AC_NO = G.GNL_AC_NO
AND F.SSPS_DL_CRT_DT = L.SSPS_DL_CRT_DT(+) AND F.SSPS_DL_ID = L.SSPS_DL_ID(+) AND F.GNL_AC_NO = L.GNL_AC_NO(+)
AND G.SSPS_DL_CRT_DT = H.SSPS_DL_CRT_DT(+) AND G.SSPS_DL_ID = H.SSPS_DL_ID(+) AND G.GNL_AC_NO = H.GNL_AC_NO(+) AND G.DL_DT = H.DL_DT(+) AND G.DL_SQ = H.DL_SQ(+)
AND F.SSPS_DL_CRT_DT = I.SSPS_DL_CRT_DT(+) AND F.SSPS_DL_ID = I.SSPS_DL_ID(+) AND F.GNL_AC_NO = I.GNL_AC_NO(+)
AND G.SSPS_DL_CRT_DT = J.SSPS_DL_CRT_DT(+) AND G.SSPS_DL_ID = J.SSPS_DL_ID(+) AND G.GNL_AC_NO = J.GNL_AC_NO(+) AND G.DL_DT = J.DL_DT(+) AND G.DL_SQ = J.DL_SQ(+)
AND G.SSPS_DL_CRT_DT = K.SSPS_DL_CRT_DT(+) AND G.SSPS_DL_ID = K.SSPS_DL_ID(+) AND G.GNL_AC_NO = K.GNL_AC_NO(+) AND G.DL_DT = K.DL_DT(+) AND G.DL_SQ = K.DL_SQ(+)
AND A.SSPS_DL_CRT_DT = #{SSPS_DL_CRT_DT} AND A.SSPS_DL_ID = #{SSPS_DL_ID}

mapper.update:
INSERT INTO NIC80B_LOG
( 	  SSPS_DL_CRT_DT
	, SSPS_DL_ID
	, SQ
	, PROC_FALG
	, PROC_CTNT
	, HNDL_DY_TM
	, HNDL_P_ENO)
VALUES
(
	  #{SSPS_DL_CRT_DT}
	, #{SSPS_DL_ID}
	, (SELECT NVL(MAX(SQ),0)+1 FROM NIC80B_LOG A WHERE A.SSPS_DL_CRT_DT= #{SSPS_DL_CRT_DT} AND A.SSPS_DL_ID = #{SSPS_DL_ID})
	, #{PROC_FALG}
	, #{PROC_CTNT, jdbcType=VARCHAR}
	, SYSDATE
	, #{HNDL_P_ENO}
)

mapper.select:
SELECT TBL.* , CASE WHEN EXISTS (SELECT 1 FROM NIC80B_HIS WHERE SSPS_DL_CRT_DT = TBL.SSPS_DL_CRT_DT AND SSPS_DL_ID = TBL.SSPS_DL_ID AND KFU_RPR_STS_CD IN ('34','44','54') AND SND_RCPT_DOC_NO != TBL.INIT_DOC_NO) THEN 'Y' END AS ADD_YN , GET_CODE_NAME('A103',TBL.RPR_CCD) AS RPR_NM , CASE WHEN EXISTS (SELECT 1 FROM NIC75B WHERE SSPS_DL_CRT_DT = TBL.SSPS_DL_CRT_DT AND RNMCNO = TBL.RNMCNO AND SSPS_DL_ID LIKE 'CTR%' AND SSPS_DL_ID != TBL.SSPS_DL_ID) THEN TBL.RNM_PR_DL_SQ ELSE 0 END AS RNM_PR_DL_SQ , FN_CDINFO_VAR('DT',TBL.DL_DT||TBL.DL_TM,'') AS DL_DT_TM_VIEW , DECODE((SELECT COUNT(*) FROM NIC40B WHERE BAS_YYMM = TO_CHAR(ADD_MONTHS(TO_DATE(TBL.SSPS_DL_CRT_DT, 'YYYYMMDD'),-1),'YYYYMM') AND RNMCNO=TBL.DL_P_RNMCNO),0,'','Y') AS LGA_AST_YN , FN_CDINFO_VAR('DPT',TBL.HANDLNG_BRN_CD,'') AS HANDLNG_BRN_NM , CASE WHEN CTR_DL_KND_CD IN ('11','12') THEN FN_CDINFO_VAR('DPT',TBL.MN_DL_DPRT_CD,'') END AS MN_DL_DPRT_NM --계좌관리점 , CASE WHEN CTR_DL_KND_CD IN ('11','12') THEN FN_CDINFO_VAR('DPT',TBL.PRFT_BRN_CD,'') END AS PRFT_BRN_NM --계좌실적점 , GET_CODE_NAME('M045',TBL.DL_TYP_CD) AS DL_TYP_CD_NM , GET_CODE_NAME('M062',TBL.CTR_DL_KND_CD) AS CTR_DL_KND_CD_NM , GET_CODE_NAME('A029',TBL.RPR_PRGRS_CCD) AS RPR_CCD_NM , (SELECT CASE WHEN (SELECT RPR_PRGRS_CCD || OK_CCD FROM NIC66B WHERE SSPS_DL_CRT_DT = T5.SSPS_DL_CRT_DT AND SSPS_DL_ID = T5.SSPS_DL_ID) = '92' THEN '' ELSE DECODE(TBL.RPR_DOC_NO_DL_YR, NULL, '', TBL.RPR_DOC_NO_DL_YR||'-') ||DECODE(TBL.RPR_DOC_NO_FNL_SQ, '0', '', TRIM(LPAD(TBL.RPR_DOC_NO_FNL_SQ, '7', '0'))) END FROM NIC84B T5 WHERE T5.ORG_SSPS_DL_CRT_DT = TBL.SSPS_DL_CRT_DT AND T5.ORG_SSPS_DL_ID = TBL.SSPS_DL_ID AND T5.RPR_DOC_NO_DL_YR = TBL.RPR_DOC_NO_DL_YR AND T5.RPR_DOC_NO_FNL_SQ = TBL.RPR_DOC_NO_FNL_SQ AND ROWNUM = 1) AS RPR_DOC_NO_FNL_SQ_CAN , CASE WHEN TBL.RPR_PRGRS_CCD = '99' THEN TBL.SND_RCPT_DOC_NO END AS RPR_DOC_NO_FNL_SQ , (SELECT FN_CDINFO_VAR('DT',SUBSTR(MAX(RPR_P_DY_TM),1,8),'') FROM NIC66B_W WHERE INST_ID = TBL.INST_ID) AS WF_END_DT , FN_CDINFO_VAR('DT',TBL.RPR_DT,'') AS RPR_DT , DECODE((SELECT COUNT(*) FROM NIC64B WHERE SSPS_DL_CRT_DT=TBL.SSPS_DL_CRT_DT AND SSPS_DL_ID=TBL.SSPS_DL_ID),0,'No','Yes') AS FILE_ATT_YN , CASE WHEN TRIM(TBL.AC_OWN_P_RLTNS_CD) IS NULL THEN '' ELSE (TBL.AC_OWN_P_RLTNS_CD|| ' / ' ||(SELECT CD_VL_NM FROM NIC95B WHERE CD='L058' AND TRNSFRM_CD = AC_OWN_P_RLTNS_CD)) END AS RLTNS_CD_NM , GET_CODE_NAME('S017', TBL.CTR_FWRD_TP_CODE) AS CTR_FWRD_TP_CODE , GET_CODE_NAME('M045', TBL.DL_TYP_CD) AS DL_TYP_NM , CASE WHEN (SELECT COUNT(*) FROM NIC80B_HIS WHERE SSPS_DL_CRT_DT = TBL.SSPS_DL_CRT_DT AND SSPS_DL_ID = TBL.SSPS_DL_ID AND KFU_RPR_STS_CD = '99') > 1 THEN 'Y' END AS EDIT_YN , (SELECT COALESCE(KFU_RPR_STS_CD, RPR_PRGRS_CCD) FROM NIC66B WHERE SSPS_DL_CRT_DT = TBL.SSPS_DL_CRT_DT AND DL_P_RNMCNO = TBL.DL_P_RNMCNO AND RNM_PR_DL_SQ = 1 AND ROWNUM = 1) AS BAS_DOC_STS_CD -- 대표문서상태코드 FROM ( SELECT '0' AS SELECTED , A.RPR_CCD , A.SSPS_DL_CRT_DT||'-'||A.SSPS_DL_ID AS SSPS_DL_CRT_DT_A , A.SSPS_DL_CRT_CCD , A.SSPS_DL_CRT_DT , C.RNMCNO , A.RNM_PR_DL_SQ , C.DL_DT , C.DL_TM , C.HANDLNG_BRN_CD , C.CSH , C.DL_TYP_CD , B.MN_DL_DPRT_CD , B.PRFT_BRN_CD , A.DL_P_RNMCNO , F.DL_P_NM , C.CNCT_AC_NO AS RL_AC_NO , C.CTR_DL_KND_CD , CASE WHEN CTR_DL_KND_CD IN ('21','22') THEN NVL(D.CPRTY_TRSNS_AC_NO, TRIM(B.ACNT_NO)) END AS CPRTY_TRSNS_AC_NO , CASE WHEN CTR_DL_KND_CD IN ('11','12') THEN B.ACNT_NO ELSE '' END AS ACNT_NO , B.GNL_AC_NO , A.RPR_PRGRS_CCD , A.RPR_DOC_NO_FNL_SQ , CASE WHEN A.RPR_PRGRS_CCD = '99' THEN TRIM(A.DOC_NO_YR) || '-' || TRIM(TO_CHAR(A.DOC_SQ, '0000000')) END AS DOC_SQ , TRIM(A.DOC_NO_YR) || '-' || TRIM(TO_CHAR(A.DOC_SQ, '0000000')) AS DOC_SQ_ORI , H.SND_RCPT_FILE_NM AS KOFIU_FILE , CASE WHEN A.RPR_PRGRS_CCD = '99' THEN H.SND_RCPT_FILE_NM END as TRSMT_ST_NM , XCL_RSN_CNTNT AS SN_COMMENT , A.SSPS_DL_ID , A.SSPS_DL_RPR_CCD , A.OK_CCD , A.SSPS_DL_ANLYS_BRN_CD , A.SSPS_DL_ANLYS_BRN_NM , H.SND_RCPT_DOC_NO , A.RPR_DOC_NO_DL_YR , A.XCL_RSN_CNTNT , A.INST_ID , F.CS_NO , F.INDV_CORP_CCD , A.RPR_DT , G.AC_OWN_P_RLTNS_CD , H.FIU_NO , H.FIU_REG_DT , CASE WHEN TRIM(G.PRXY_CS_NO) IS NOT NULL OR TRIM(G.AC_OWN_P_RLTNS_CD) IS NOT NULL THEN 'Y' ELSE NULL END PRXY_YN , J.CS_NO AS PRXY_CS_NO , A.STR_YN , CTR_FWRD_RSLT_CTNT , CTR_FWRD_TP_CODE , C.DTLS_TRDG_NAME , CASE WHEN LENGTH(H.RPR_OGN_CD) = 4 THEN '보기' WHEN NVL(A.KFU_RPR_STS_CD, A.RPR_PRGRS_CCD) IN ('10','40','50') THEN '보기' ELSE '수정' END AS XML_FILE_EDIT , TO_CHAR(A.KFU_RPR_DT, 'YYYY-MM-DD') AS KFU_RPR_DT , NVL(A.KFU_RPR_STS_CD, A.RPR_PRGRS_CCD) AS KFU_RPR_STS_CD , GET_CODE_NAME('S060', NVL(A.KFU_RPR_STS_CD, A.RPR_PRGRS_CCD)) AS KFU_RPR_STS_NM , H.RPR_OGN_CD , A.CTR_FAITH_CHK_YN
, (SELECT MAX(SND_RCPT_DOC_NO) KEEP (DENSE_RANK FIRST ORDER BY RRPR_SQ, SQ) FROM NIC80B_HIS WHERE SSPS_DL_CRT_DT = A.SSPS_DL_CRT_DT AND SSPS_DL_ID = A.SSPS_DL_ID AND KFU_RPR_STS_CD = '10' AND ( (SND_RCPT_DOC_NO = H.SND_RCPT_DOC_NO AND A.KFU_RPR_STS_CD IN ('34','44','54')) OR SND_RCPT_DOC_NO != H.SND_RCPT_DOC_NO ) ) AS INIT_DOC_NO --최초문서번호 , F.SPRN_KEEP_TAGT_YN , F.CS_NO AS AML_CUST_ID FROM NIC66B A , NIC71B B , NIC75B C , NIC83B D , NIC80B H , NIC70B F , NIC98B G , NIC01B J WHERE A.SSPS_DL_CRT_DT = B.SSPS_DL_CRT_DT AND A.SSPS_DL_ID = B.SSPS_DL_ID AND B.SSPS_DL_CRT_DT = C.SSPS_DL_CRT_DT AND B.SSPS_DL_ID = C.SSPS_DL_ID AND B.GNL_AC_NO = C.GNL_AC_NO AND C.SSPS_DL_CRT_DT = D.SSPS_DL_CRT_DT(+) AND C.SSPS_DL_ID = D.SSPS_DL_ID(+) AND C.GNL_AC_NO = D.GNL_AC_NO(+) AND C.DL_DT = D.DL_DT(+) AND C.DL_SQ = D.DL_SQ(+) AND A.SSPS_DL_CRT_DT = H.SSPS_DL_CRT_DT(+) AND A.SSPS_DL_ID = H.SSPS_DL_ID(+) AND A.SSPS_DL_CRT_DT = F.SSPS_DL_CRT_DT(+) AND A.DL_P_RNMCNO = F.DL_P_RNMCNO(+) AND A.SSPS_DL_CRT_CCD IN ('CTR','CAC') AND A.SSPS_DL_CRT_DT = G.SSPS_DL_CRT_DT(+) AND A.SSPS_DL_ID = G.SSPS_DL_ID(+) AND G.PRXY_RNMCNO = J.RNMCNO(+)
AND #{branchCode} IN (SELECT MN_DL_BRN_CD FROM NIC73B WHERE SSPS_DL_CRT_DT = A.SSPS_DL_CRT_DT AND SSPS_DL_ID = A.SSPS_DL_ID)
AND C.DL_DT BETWEEN #{stDate} AND #{edDate}
AND A.RPR_DT BETWEEN #{stDate} AND #{edDate}
AND F.CS_NO = #{CS_NO, jdbcType=VARCHAR}
AND F.DL_P_NM LIKE '%'|| #{CS_NM, jdbcType=VARCHAR} ||'%'
AND A.OK_CCD = #{OK_CCD, jdbcType=VARCHAR}
AND A.RPR_PRGRS_CCD IN ('9', '99', '98', '97')
AND NVL(A.KFU_RPR_STS_CD, A.RPR_PRGRS_CCD) = #{RPR_PRGRS_CCD, jdbcType=VARCHAR}
AND A.DL_P_RNMCNO = (SELECT RNMCNO FROM NIC17B WHERE ACNT_NO LIKE #{ACNT_NO, jdbcType=VARCHAR} || '%')
) TBL

SELECT A.CNTNT , A.CD_NM , (SELECT CD_NM FROM NIC91B WHERE CD = A.CD) AS GR_CD_NM FROM NIC92B A WHERE A.CD = #{SCH_CD}
AND (A.CNTNT LIKE #{SCH_VAL}||'%' OR A.CD_NM LIKE '%'||#{SCH_VAL}||'%')
AND A.USE_F = 'Y' ORDER BY CD_RNK_SQ

SELECT RNMCNO AS RNMCNO , CS_NO , RPAD(SUBSTR(CS_NO,1,LENGTH(CS_NO)-6),LENGTH(CS_NO),'*') AS CS_NO_VIEW , CS_NM , (SELECT RPAD(SUBSTR(GNL_AC_NO,1,8),14,'*') AS GNL_AC_NO_VIEW FROM NIC17B WHERE RNMCNO = A.RNMCNO AND ROWNUM = 1) AS GNL_AC_NO_VIEW , RNM_CNFR_CCD , GET_CODE_NAME('M002',TRIM(RNM_CNFR_CCD)) AS RNM_CNFR_CCD_NM , CORP_RGST_NO , NVL(TRIM(NTN_CD),'KR') AS NTN_CD , GET_CODE_NAME('M004',NVL(TRIM(NTN_CD),'KR')) AS NTN_NM , INDV_CORP_CCD , DECODE(INDV_CORP_CCD,'1','개인','2','법인',INDV_CORP_CCD) AS INDV_CORP_CCD_NM , AML_JOB_GUBN , LG_AMT_ASTS_F , NPRFT_GROUP_F , CS_DLT_DT FROM NIC01B A WHERE 1=1
AND RNMCNO = #{RNMCNO}
AND CS_NO LIKE #{CS_NO}||'%'
AND CS_NM LIKE #{CS_NM}||'%'
AND CS_NM = #{CS_NM}
AND RNMCNO IN (SELECT RNMCNO FROM NIC17B WHERE GNL_AC_NO = #{GNL_AC_NO})

mapper.update:
/* AML_20_02_02_90_doSave_NIC66B */
UPDATE NIC66B
   SET HNDL_DY_TM = SYSDATE
     , HNDL_P_ENO = #{HNDL_P_ENO}   

    , RPR_CCD = #{RPR_CCD}
    , CAC_UPD_RSN_CNTNT = #{CAC_UPD_RSN_CNTNT}

 WHERE SSPS_DL_CRT_DT = #{SSPS_DL_CRT_DT}
   AND SSPS_DL_ID = #{SSPS_DL_ID}

/* AML_20_02_02_90_doSave_NIC84B */
MERGE INTO NIC84B
	USING DUAL
	ON (SSPS_DL_CRT_DT = #{SSPS_DL_CRT_DT}
	  AND SSPS_DL_ID = #{SSPS_DL_ID}
    )
	WHEN MATCHED THEN

	UPDATE
	   SET HNDL_DY_TM = SYSDATE
	       , HNDL_P_ENO = #{HNDL_P_ENO}
	       , RPR_DOC_NO_DL_YR = 0 + SUBSTR(REPLACE(#{CTR04}, '-'), 1, 4)    
	       , RPR_DOC_NO_FNL_SQ = 0 + SUBSTR(REPLACE(#{CTR04}, '-'), 5)
	       , ORG_SSPS_DL_CRT_DT = #{SSPS_DL_CRT_DT}
	       , ORG_SSPS_DL_ID = #{SSPS_DL_ID}	   
	WHERE SSPS_DL_CRT_DT = #{SSPS_DL_CRT_DT}
	  AND SSPS_DL_ID = #{SSPS_DL_ID}

	WHEN NOT MATCHED THEN

	INSERT (
		  SSPS_DL_CRT_DT
 		, SSPS_DL_ID
		, RPR_DOC_NO_DL_YR
		, RPR_DOC_NO_FNL_SQ
  		, HNDL_DY_TM
  		, HNDL_P_ENO
     	, ORG_SSPS_DL_CRT_DT
     	, ORG_SSPS_DL_ID
	) VALUES (
		  #{SSPS_DL_CRT_DT}
 		, #{SSPS_DL_ID}
		, 0 + SUBSTR(REPLACE(#{CTR04}, '-'), 1, 4)   
		, 0 + SUBSTR(REPLACE(#{CTR04}, '-'), 5)
  		, SYSDATE
  		, #{HNDL_P_ENO}
     	, #{SSPS_DL_CRT_DT}
     	, #{SSPS_DL_ID}
	)

