	     , AC_OWN_P_RLTNS_KFU_CD = #{AC_OWN_P_RLTNS_KFU_CD}
	     , AC_OWN_P_RLTNS_KFU_NM = #{AC_OWN_P_RLTNS_KFU_NM}
	WHERE SSPS_DL_CRT_DT = #{SSPS_DL_CRT_DT}
	  AND SSPS_DL_ID = #{SSPS_DL_ID}
	  AND GNL_AC_NO = #{GNL_AC_NO}
	  AND GDS_NO = #{GDS_NO}
	  AND DL_DT = #{DL_DT}
	  AND DL_SQ = #{DL_SQ}

	WHEN NOT MATCHED THEN

	INSERT (
		  SSPS_DL_CRT_DT
 		, SSPS_DL_ID
		, GNL_AC_NO
		, GDS_NO
  		, DL_DT
  		, DL_SQ
     	, PRXY_NM
     	, PRXY_RNM_NO_CCD
     	, PRXY_RNMCNO
     	, PRXY_CS_NO
     	, PRXY_AREA
     	, PRXY_ECNO
     	, PRXY_NO
     	, PRXY_NTNLT_CD
     	, PRXY_NTNLT_NM
     	, AC_OWN_P_RLTNS_KFU_CD
     	, AC_OWN_P_RLTNS_KFU_NM
     	, HNDL_DY_TM
     	, HNDL_P_ENO
	) VALUES (
		  #{SSPS_DL_CRT_DT}
 		, #{SSPS_DL_ID}
		, #{GNL_AC_NO}
		, #{GDS_NO}
  		, #{DL_DT}
  		, #{DL_SQ}
     	, #{PRXY_NM}
     	, #{PRXY_RNM_NO_CCD}
     	, #{PRXY_RNMCNO}
