INSERT INTO NIC80B_ADD (
    SSPS_DL_CRT_DT
  , SSPS_DL_ID
  , RRPR_SQ
  , SQ
  , KFU_RPR_STS_CD
  , KFU_RPR_RSLT_CTNT
  , SND_RCPT_DOC_NO
  , SND_RCPT_FILE_NM
  , HNDL_DY_TM
  , DOC_NO_YR
  , DOC_NO
) VALUES (
    #{SSPS_DL_CRT_DT}
  , #{SSPS_DL_ID}
  , (SELECT MAX(RRPR_SQ)
       FROM NIC80B_ADD
      WHERE SSPS_DL_CRT_DT = #{SSPS_DL_CRT_DT}
          AND SSPS_DL_ID = #{SSPS_DL_ID})
  , (SELECT NVL(MAX(SQ) KEEP (DENSE_RANK FIRST ORDER BY RRPR_SQ DESC, SQ DESC), 0)+1
               FROM NIC80B_ADD
      WHERE SSPS_DL_CRT_DT = #{SSPS_DL_CRT_DT}
          AND SSPS_DL_ID = #{SSPS_DL_ID})
  , #{KFU_RPR_STS_CD}
  , #{KFU_RPR_RSLT_CTNT}
  , (SELECT MAX(SND_RCPT_DOC_NO) KEEP (DENSE_RANK FIRST ORDER BY RRPR_SQ DESC, SQ DESC)
       FROM NIC80B_ADD
      WHERE SSPS_DL_CRT_DT = #{SSPS_DL_CRT_DT}
          AND SSPS_DL_ID = #{SSPS_DL_ID})
  , CASE WHEN #{KFU_RPR_STS_CD} = '99' THEN #{SND_RCPT_FILE_NM}
            ELSE (SELECT MAX(SND_RCPT_FILE_NM) KEEP (DENSE_RANK FIRST ORDER BY RRPR_SQ DESC, SQ DESC)
                       FROM NIC80B_ADD
                     WHERE SSPS_DL_CRT_DT = #{SSPS_DL_CRT_DT}
                         AND SSPS_DL_ID = #{SSPS_DL_ID}) END
  , SYSDATE
  , CASE WHEN #{KFU_RPR_STS_CD} = '99' THEN #{DOC_NO_YR}
            ELSE (SELECT MAX(DOC_NO_YR) KEEP (DENSE_RANK FIRST ORDER BY RRPR_SQ DESC, SQ DESC)
                       FROM NIC80B_ADD
                     WHERE SSPS_DL_CRT_DT = #{SSPS_DL_CRT_DT}
                         AND SSPS_DL_ID = #{SSPS_DL_ID}) END
  , CASE WHEN #{KFU_RPR_STS_CD} = '99' THEN TO_NUMBER(#{DOC_NO})
            ELSE (SELECT MAX(DOC_NO) KEEP (DENSE_RANK FIRST ORDER BY RRPR_SQ DESC, SQ DESC)
                       FROM NIC80B_ADD
                     WHERE SSPS_DL_CRT_DT = #{SSPS_DL_CRT_DT}
                         AND SSPS_DL_ID = #{SSPS_DL_ID}) END
)

