  UPDATE NIC66B  
  SET RPR_PRGRS_CCD = DECODE(RRPR_YN,'Y', RPR_PRGRS_CCD, #{RPR_PRGRS_CCD} )
    , KFU_RPR_DT = CASE WHEN KFU_RPR_DT IS NULL THEN SYSDATE ELSE KFU_RPR_DT END
    , KFU_RPR_STS_CD = CASE WHEN NVL(RRPR_YN,'N') = 'N' AND KFU_RPR_STS_CD IS NOT NULL THEN #{RPR_PRGRS_CCD} ELSE KFU_RPR_STS_CD END
    , KFU_RRPR_STS_CD = DECODE(RRPR_YN,'Y', #{RPR_PRGRS_CCD}, KFU_RRPR_STS_CD)
    , HNDL_DY_TM = SYSDATE      
    , HNDL_P_ENO = #{HNDL_P_ENO}     
WHERE SSPS_DL_CRT_DT = #{SSPS_DL_CRT_DT}  
  AND SSPS_DL_ID = #{SSPS_DL_ID}
